const uploadDir = "./public"
const maxUploadSize = 10 << 20 // 10 MB

func main() {
	// Create the upload directory if it doesn't exist
	if _, err := os.Stat(uploadDir); os.IsNotExist(err) {
		err = os.MkdirAll(uploadDir, 0755)
		if err != nil {
			log.Fatalf("Failed to create upload directory: %v", err)
		}
	}

	http.HandleFunc("/upload", uploadHandler)
	// Serve static files from the public directory.
	// This makes uploaded files accessible via "/public/filename".
	http.Handle("/public/", http.StripPrefix("/public/", http.FileServer(http.Dir(uploadDir))))

	fmt.Printf("Server started on :8080\n")
	fmt.Printf("Upload endpoint: POST /upload (form field 'file')\n")
	fmt.Printf("Files will be served from /public/\n")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Limit the total request body size to prevent abuse
	r.Body = http.MaxBytesReader(w, r.Body, maxUploadSize)

	// Parse multipart form with a max memory limit.
	// Files larger than this will be stored on disk.
	err := r.ParseMultipartForm(maxUploadSize)
	if err != nil {
		log.Printf("Error parsing multipart form: %v", err)
		if strings.Contains(err.Error(), "too large") {
			http.Error(w, "The uploaded file is too large. Max size is 10MB.", http.StatusRequestEntityTooLarge)
		} else {
			http.Error(w, "Error processing form data", http.StatusBadRequest)
		}
		return
	}

	// Retrieve the file from the form data under the field name "file"
	file, handler, err := r.FormFile("file")
	if err != nil {
		log.Printf("Error retrieving file from form: %v", err)
		http.Error(w, "Error retrieving 'file' from form. Ensure the field name is 'file'.", http.StatusBadRequest)
		return
	}
	defer file.Close() // Ensure the uploaded file is closed

	// Generate a unique filename using UUID and preserve the original extension
	extension := strings.ToLower(filepath.Ext(handler.Filename))
	if extension == "" {
		extension = ".bin" // Default extension for files without one
	}
	newFileName := uuid.New().String() + extension
	destinationPath := filepath.Join(uploadDir, newFileName)

	// Create the destination file on the server
	dst, err := os.Create(destinationPath)
	if err != nil {
		log.Printf("Error creating the file on disk: %v", err)
		http.Error(w, "Error saving file on server", http.StatusInternalServerError)
		return
	}
	defer dst.Close() // Ensure the created file is closed

	// Copy the uploaded file's content to the destination file
	if _, err := io.Copy(dst, file); err != nil {
		log.Printf("Error copying file content: %v", err)
		http.Error(w, "Error writing file content", http.StatusInternalServerError)
		return
	}

	// Construct the public path to the uploaded file
	uploadedFilePath := "/public/" + newFileName

	// Respond with the public file path in JSON format
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"filepath": uploadedFilePath})
}